//find-subfunction.js

import { defined } from '../../utils/zcutils';
import { getAutoTimeSubFunction } from '../../formatter/formatter';
import { extent } from '../../scale/domain/extent';

//!Note: Function has no usage in source code. Need to be removed
export function findSubFunction(processor, data) {
    let dataSet = processor.dataset,
        xExtent = extent(
            data.map(d => d.data),
            dataSet.xidx
        );

    let columnConfig = dataSet.getColumn('x').time || {},
        formattingSubFunction = columnConfig && columnConfig.subfunction;

    if (!defined(formattingSubFunction) || formattingSubFunction === 'AUTO') {
        // set sub function
        var info = getAutoTimeSubFunction(xExtent[1] - xExtent[0]);
        columnConfig.subfunction = info.subFunction;
    }
}
